8	#include <rime/build_config.h>
9	
10	#include <algorithm>
11	#include <boost/algorithm/string.hpp>
12	#include <filesystem>
13	#include <boost/uuid/random_generator.hpp>
14	#include <boost/uuid/uuid.hpp>
15	#include <boost/uuid/uuid_io.hpp>
16	#include <rime/common.h>
17	#include <rime/resource.h>
18	#include <rime/schema.h>
19	#include <rime/service.h>
20	#include <rime/setup.h>
21	#include <rime/ticket.h>
22	#include <rime/algo/fs.h>
23	#include <rime/algo/utilities.h>
24	#include <rime/dict/dictionary.h>
25	#include <rime/dict/dict_compiler.h>
26	#include <rime/lever/deployment_tasks.h>
27	#include <rime/lever/user_dict_manager.h>
28	#ifdef _WIN32
29	#include <windows.h>
30	#endif
31	
32	namespace fs = std::filesystem;
33	
34	namespace rime {
35	
36	DetectModifications::DetectModifications(TaskInitializer arg) {
37	  try {
38	    data_dirs_ = std::any_cast<vector<path>>(arg);
39	  } catch (const std::bad_any_cast&) {
40	    LOG(ERROR) << "DetectModifications: invalid arguments.";
41	  }
42	}
43	
44	bool DetectModifications::Run(Deployer* deployer) {
45	  time_t last_modified = 0;
46	  try {
47	    for (auto dir : data_dirs_) {
48	      path p = fs::canonical(dir);
49	      last_modified = (std::max)(last_modified,
50	                                 filesystem::to_time_t(fs::last_write_time(p)));
51	      if (fs::is_directory(p)) {
52	        for (fs::directory_iterator iter(p), end; iter != end; ++iter) {
53	          path entry(iter->path());
54	          if (fs::is_regular_file(fs::canonical(entry)) &&
55	              entry.extension().u8string() == ".yaml" &&
56	              entry.filename().u8string() != "user.yaml") {
57	            last_modified =
58	                (std::max)(last_modified,
59	                           filesystem::to_time_t(fs::last_write_time(entry)));
60	          }
61	        }
62	      }
63	    }
64	  } catch (const fs::filesystem_error& ex) {
65	    LOG(ERROR) << "Error reading file information: " << ex.what();
66	    return true;
67	  }
68	
69	  // TODO: store as 64-bit number to avoid the year 2038 problem
70	  int last_build_time = 0;
71	  {
72	    the<Config> user_config(Config::Require("user_config")->Create("user"));
73	    user_config->GetInt("var/last_build_time", &last_build_time);
74	  }
75	  if (last_modified > (time_t)last_build_time) {
76	    LOG(INFO) << "modifications detected. workspace needs update.";
77	    return true;
78	  }
79	  return false;
80	}
81	
82	bool InstallationUpdate::Run(Deployer* deployer) {
83	  LOG(INFO) << "updating rime installation info.";
84	  const path& shared_data_path(deployer->shared_data_dir);
85	  const path& user_data_path(deployer->user_data_dir);
86	  if (!fs::exists(user_data_path)) {
87	    LOG(INFO) << "creating user data dir: " << user_data_path;
88	    std::error_code ec;
89	    if (!fs::create_directories(user_data_path, ec)) {
90	      LOG(ERROR) << "Error creating user data dir: " << user_data_path;
91	    }
92	  }
93	  path installation_info(user_data_path / "installation.yaml");
94	  Config config;
95	  string installation_id;
96	  string last_distro_code_name;
97	  string last_distro_version;
98	  string last_rime_version;
99	  if (config.LoadFromFile(installation_info)) {
100	    if (config.GetString("installation_id", &installation_id)) {
101	      LOG(INFO) << "installation info exists. installation id: "
102	                << installation_id;
103	      // for now:
104	      deployer->user_id = installation_id;
105	    }
106	    string sync_dir;
107	    if (config.GetString("sync_dir", &sync_dir)) {
108	      deployer->sync_dir = path(sync_dir);
109	    } else {
110	      deployer->sync_dir = user_data_path / "sync";
111	    }
112	    LOG(INFO) << "sync dir: " << deployer->sync_dir;
113	    bool backup_config_files;
114	    if (config.GetBool("backup_config_files", &backup_config_files)) {
115	      deployer->backup_config_files = backup_config_files;
116	    }
117	    if (config.GetString("distribution_code_name", &last_distro_code_name)) {
118	      LOG(INFO) << "previous distribution: " << last_distro_code_name;
119	    }
120	    if (config.GetString("distribution_version", &last_distro_version)) {
121	      LOG(INFO) << "previous distribution version: " << last_distro_version;
122	    }
123	    if (config.GetString("rime_version", &last_rime_version)) {
124	      LOG(INFO) << "previous Rime version: " << last_rime_version;
125	    }
126	  }
127	  if (!installation_id.empty() &&
128	      last_distro_code_name == deployer->distribution_code_name &&
129	      last_distro_version == deployer->distribution_version &&
130	      last_rime_version == RIME_VERSION) {
131	    return true;
132	  }
133	  LOG(INFO) << "creating installation info.";
134	  time_t now = time(NULL);
135	  string time_str(ctime(&now));
136	  boost::trim(time_str);
137	  if (installation_id.empty()) {
138	    installation_id =
139	        boost::uuids::to_string(boost::uuids::random_generator()());
140	    LOG(INFO) << "generated installation id: " << installation_id;
141	    // for now:
142	    deployer->user_id = installation_id;
143	    config.SetString("installation_id", installation_id);
144	    config.SetString("install_time", time_str);
145	  } else {
146	    config.SetString("update_time", time_str);
147	  }
148	  if (!deployer->distribution_name.empty()) {
149	    config.SetString("distribution_name", deployer->distribution_name);
150	    LOG(INFO) << "distribution: " << deployer->distribution_name;
151	  }
152	  if (!deployer->distribution_code_name.empty()) {
153	    config.SetString("distribution_code_name",
154	                     deployer->distribution_code_name);
155	    LOG(INFO) << "distribution code name: " << deployer->distribution_code_name;
156	  }
157	  if (!deployer->distribution_version.empty()) {
158	    config.SetString("distribution_version", deployer->distribution_version);
159	    LOG(INFO) << "distribution version: " << deployer->distribution_version;
160	  }
161	  config.SetString("rime_version", RIME_VERSION);
162	  LOG(INFO) << "Rime version: " << RIME_VERSION;
163	  return config.SaveToFile(installation_info);
164	}
165	
166	bool WorkspaceUpdate::Run(Deployer* deployer) {
167	  LOG(INFO) << "updating workspace.";
168	  {
169	    the<DeploymentTask> t;
170	    t.reset(new ConfigFileUpdate("default.yaml", "config_version"));
171	    t->Run(deployer);
172	    // Deprecated: symbols.yaml is only used as source file
173	    // t.reset(new ConfigFileUpdate("symbols.yaml", "config_version"));
174	    // t->Run(deployer);
175	    t.reset(new SymlinkingPrebuiltDictionaries);
176	    t->Run(deployer);
177	  }
178	
179	  the<Config> config(Config::Require("config")->Create("default"));
180	  if (!config) {
181	    LOG(ERROR) << "Error loading default config.";
182	    return false;
183	  }
184	  auto schema_list = config->GetList("schema_list");
185	  if (!schema_list) {
186	    LOG(WARNING) << "schema list not defined.";
187	    return false;
188	  }
189	
190	  LOG(INFO) << "updating schemas.";
191	  int success = 0;
192	  int failure = 0;
193	  map<string, path> schemas;
194	  the<ResourceResolver> resolver(Service::instance().CreateResourceResolver(
195	      {"schema_source_file", "", ".schema.yaml"}));
196	  auto build_schema = [&](const string& schema_id, bool as_dependency = false) {
197	    if (schemas.find(schema_id) != schemas.end())  // already built
198	      return;
199	    LOG(INFO) << "schema: " << schema_id;
200	    path schema_path;
201	    if (schemas.find(schema_id) == schemas.end()) {
202	      schema_path = resolver->ResolvePath(schema_id);
203	      schemas[schema_id] = schema_path;
204	    } else {
205	      schema_path = schemas[schema_id];
206	    }
207	    if (schema_path.empty() || !fs::exists(schema_path)) {
208	      if (as_dependency) {
209	        LOG(WARNING) << "missing input schema; skipped unsatisfied dependency: "
210	                     << schema_id;
211	      } else {
212	        LOG(ERROR) << "missing input schema: " << schema_id;
213	        ++failure;
214	      }
215	      return;
216	    }
217	    the<DeploymentTask> t(new SchemaUpdate(schema_path));
218	    if (t->Run(deployer))
219	      ++success;
220	    else
221	      ++failure;
222	  };
223	  auto schema_component = Config::Require("schema");
224	  for (auto it = schema_list->begin(); it != schema_list->end(); ++it) {
225	    auto item = As<ConfigMap>(*it);
226	    if (!item)
227	      continue;
228	    auto schema_property = item->GetValue("schema");
229	    if (!schema_property)
230	      continue;
231	    const string& schema_id = schema_property->str();
232	    build_schema(schema_id);
233	    the<Config> schema_config(schema_component->Create(schema_id));
234	    if (!schema_config)
235	      continue;
236	    if (auto dependencies = schema_config->GetList("schema/dependencies")) {
237	      for (auto d = dependencies->begin(); d != dependencies->end(); ++d) {
238	        auto dependency = As<ConfigValue>(*d);
239	        if (!dependency)
240	          continue;
241	        const string& dependency_id = dependency->str();
242	        bool as_dependency = true;
243	        build_schema(dependency_id, as_dependency);
244	      }
245	    }
246	  }
247	  LOG(INFO) << "finished updating schemas: " << success << " success, "
248	            << failure << " failure.";
249	
250	  the<Config> user_config(Config::Require("user_config")->Create("user"));
251	  // TODO: store as 64-bit number to avoid the year 2038 problem
252	  user_config->SetInt("var/last_build_time", (int)time(NULL));
253	
254	  return failure == 0;
255	}
256	
257	SchemaUpdate::SchemaUpdate(TaskInitializer arg) : verbose_(false) {
258	  try {
259	    source_path_ = std::any_cast<path>(arg);
260	  } catch (const std::bad_any_cast&) {
261	    LOG(ERROR) << "SchemaUpdate: invalid arguments.";
262	  }
263	}
264	
265	static bool MaybeCreateDirectory(path dir) {
266	  std::error_code ec;
267	  if (fs::create_directories(dir, ec)) {
268	    return true;
269	  }
270	
271	  if (fs::exists(dir)) {
272	    return true;
273	  }
274	  LOG(ERROR) << "error creating directory '" << dir << "'.";
275	  return false;
276	}
277	
278	static bool RemoveVersionSuffix(string* version, const string& suffix) {
279	  size_t suffix_pos = version->find(suffix);
280	  if (suffix_pos != string::npos) {
281	    version->erase(suffix_pos);
282	    return true;
283	  }
284	  return false;
285	}
286	
287	static bool TrashDeprecatedUserCopy(const path& shared_copy,
288	                                    const path& user_copy,
289	                                    const string& version_key,
290	                                    const path& trash) {
291	  if (!fs::exists(shared_copy) || !fs::exists(user_copy) ||
292	      fs::equivalent(shared_copy, user_copy)) {
293	    return false;
294	  }
295	  string shared_copy_version;
296	  string user_copy_version;
297	  Config shared_config;
298	  if (shared_config.LoadFromFile(shared_copy)) {
299	    shared_config.GetString(version_key, &shared_copy_version);
300	    // treat "X.Y.minimal" as equal to (not greater than) "X.Y"
301	    // to avoid trashing the user installed full version
302	    RemoveVersionSuffix(&shared_copy_version, ".minimal");
303	  }
304	  Config user_config;
305	  bool is_customized_user_copy =
306	      user_config.LoadFromFile(user_copy) &&
307	      user_config.GetString(version_key, &user_copy_version) &&
308	      RemoveVersionSuffix(&user_copy_version, ".custom.");
309	  int cmp = CompareVersionString(shared_copy_version, user_copy_version);
310	  // rime-installed user copy of the same version should be kept for integrity.
311	  // also it could have been manually edited by user.
312	  if (cmp > 0 || (cmp == 0 && is_customized_user_copy)) {
313	    if (!MaybeCreateDirectory(trash)) {
314	      return false;
315	    }
316	    path backup = trash / user_copy.filename();
317	    std::error_code ec;
318	    fs::rename(user_copy, backup, ec);
319	    if (ec) {
320	      LOG(ERROR) << "error trashing file " << user_copy;
321	      return false;
322	    }
323	    return true;
324	  }
325	  return false;
326	}
327	
328	bool SchemaUpdate::Run(Deployer* deployer) {
329	  if (!fs::exists(source_path_)) {
330	    LOG(ERROR) << "Error updating schema: nonexistent file '" << source_path_
331	               << "'.";
332	    return false;
333	  }
334	  string schema_id;
335	  the<Config> config(new Config);
336	  if (!config->LoadFromFile(source_path_) ||
337	      !config->GetString("schema/schema_id", &schema_id) || schema_id.empty()) {
338	    LOG(ERROR) << "invalid schema definition in '" << source_path_ << "'.";
339	    return false;
340	  }
341	
342	  the<DeploymentTask> config_file_update(
343	      new ConfigFileUpdate(schema_id + ".schema.yaml", "schema/version"));
344	  if (!config_file_update->Run(deployer)) {
345	    return false;
346	  }
347	  // reload compiled config
348	  config.reset(Config::Require("schema")->Create(schema_id));
349	  string dict_name;
350	  if (!config->GetString("translator/dictionary", &dict_name)) {
351	    // not requiring a dictionary
352	    return true;
353	  }
354	  Schema schema(schema_id, config.release());
355	  the<Dictionary> dict(
356	      Dictionary::Require("dictionary")->Create({&schema, "translator"}));
357	  if (!dict) {
358	    LOG(ERROR) << "Error creating dictionary '" << dict_name << "'.";
359	    return false;
360	  }
361	
362	  LOG(INFO) << "preparing dictionary '" << dict_name << "'.";
363	  const path& user_data_path(deployer->user_data_dir);
364	  if (!MaybeCreateDirectory(deployer->staging_dir)) {
365	    return false;
366	  }
367	  DictCompiler dict_compiler(dict.get());
368	  if (verbose_) {
369	    dict_compiler.set_options(DictCompiler::kRebuild | DictCompiler::kDump);
370	  }
371	  the<ResourceResolver> resolver(
372	      Service::instance().CreateDeployedResourceResolver(
373	          {"compiled_schema", "", ".schema.yaml"}));
374	  auto compiled_schema = resolver->ResolvePath(schema_id);
375	  if (!dict_compiler.Compile(compiled_schema)) {
376	    LOG(ERROR) << "dictionary '" << dict_name << "' failed to compile.";
377	    return false;
378	  }
379	  LOG(INFO) << "dictionary '" << dict_name << "' is ready.";
380	  return true;
381	}
