393	static bool ConfigNeedsUpdate(Config* config) {
394	  auto build_info = (*config)["__build_info"];
395	  if (!build_info.IsMap()) {
396	    LOG(INFO) << "missing build info";
397	    return true;
398	  }
399	  auto timestamps = build_info["timestamps"];
400	  if (!timestamps.IsMap()) {
401	    LOG(INFO) << "missing timestamps";
402	    return true;
403	  }
404	  the<ResourceResolver> resolver(Service::instance().CreateResourceResolver(
405	      {"config_source_file", "", ".yaml"}));
406	  for (auto entry : *timestamps.AsMap()) {
407	    auto value = As<ConfigValue>(entry.second);
408	    int recorded_time = 0;
409	    if (!value || !value->GetInt(&recorded_time)) {
410	      LOG(WARNING) << "invalid timestamp for " << entry.first;
411	      return true;
412	    }
413	    path source_file = resolver->ResolvePath(entry.first);
414	    if (!fs::exists(source_file)) {
415	      if (recorded_time) {
416	        LOG(INFO) << "source file no longer exists: " << source_file;
417	        return true;
418	      }
419	      continue;
420	    }
421	    if (recorded_time !=
422	        (int)filesystem::to_time_t(fs::last_write_time(source_file))) {
423	      LOG(INFO) << "source file " << (recorded_time ? "changed: " : "added: ")
424	                << source_file;
425	      return true;
426	    }
427	  }
428	  return false;
429	}
