431	bool ConfigFileUpdate::Run(Deployer* deployer) {
432	  const path shared_data_path(deployer->shared_data_dir);
433	  const path user_data_path(deployer->user_data_dir);
434	  // trash deprecated user copy created by an older version of Rime
435	  path source_config_path(shared_data_path / file_name_);
436	  path dest_config_path(user_data_path / file_name_);
437	  path trash = user_data_path / "trash";
438	  if (TrashDeprecatedUserCopy(source_config_path, dest_config_path,
439	                              version_key_, trash)) {
440	    LOG(WARNING) << "deprecated user copy of '" << file_name_
441	                 << "' is moved to " << trash;
442	  }
443	  // build the config file if needs update
444	  the<Config> config(Config::Require("config")->Create(file_name_));
445	  if (ConfigNeedsUpdate(config.get())) {
446	    if (!MaybeCreateDirectory(deployer->staging_dir)) {
447	      return false;
448	    }
449	    config.reset(Config::Require("config_builder")->Create(file_name_));
450	  }
451	  return true;
452	}
