527	static bool IsCustomizedCopy(const path& file_path) {
528	  auto file_name = file_path.filename().u8string();
529	  if (boost::ends_with(file_name, ".yaml") &&
530	      !boost::ends_with(file_name, ".custom.yaml")) {
531	    Config config;
532	    string checksum;
533	    if (config.LoadFromFile(file_path) &&
534	        config.GetString("customization", &checksum)) {
535	      return true;
536	    }
537	  }
538	  return false;
